B.TH=new A.K("Introdu\xe7\xe3o","\xdaltima actualizaci\xf3n: Julio de 2026")
B.Tc=new A.K("\xbfQu\xe9 es PerfectGest I?","App de gesti\xf3n en el tel\xe9fono, con datos locales (SQLite). No hay \xabcuenta en la nube\xbb PerfectGest para clientes, presupuestos o caja.")
B.TW=new A.K("\xbfFunciona sin internet?","S\xed, uso diario offline-first. Servicios Google opcionales (Analytics, Remote Config, Firestore m\xednimo de elegibilidad) pueden usar red cuando est\xe1n activos.")
B.Tz=new A.K("\xbfPuedo usar la app sin suscripci\xf3n?","S\xed, para explorar (navegar pantallas y consultar la interfaz). Las operaciones (crear clientes, presupuestos comerciales o fiscales, caja; generar PDF de gesti\xf3n; restaurar backup cifrado; y dem\xe1s acciones condicionadas) requieren Plan Pro. Al intentar una operaci\xf3n sin suscripci\xf3n aparece un aviso con el plan (referencia R$ 9,90/mes; precio en Google Play) y Suscribirse o Continuar explorando los recursos de la aplicaci\xf3n.")
B.TX=new A.K("\xbfC\xf3mo funciona el Plan Pro?","Suscripci\xf3n mensual o anual en Google Play: clientes, presupuestos, caja y PDF sin l\xedmite pr\xe1ctico; restauraci\xf3n de backup cifrado; tarjeta interactiva (vCard, QR, vista previa). Gestionar en Ajustes \u2192 Suscripci\xf3n Google Play.")
B.U8=new A.K("\xbfD\xf3nde gestiono la suscripci\xf3n?","Ajustes \u2192 Suscripci\xf3n Google Play. Cancelaci\xf3n: Play Store \u2192 Pagos y suscripciones.")
B.TR=new A.K("\xbfQu\xe9 es la pesta\xf1a Presup./NF-e/NFS-e?","Presupuesto fiscal local (productos y servicios, c\xf3digos NCM/CFOP/LC 116, PDF de apoyo) y consulta/registro de c\xf3digos. No emite NF-e ni NFS-e electr\xf3nica ante la autoridad fiscal.")
B.UI=new A.K("\xbfQu\xe9 es la tarjeta de visita digital?","En Empresa, edita datos profesionales (no clientes ni caja). Compartir tarjeta genera PNG en la hoja de compartir. Tras la primera tarjeta, sin Plan Pro queda en modo est\xe1tico (puede compartir el PNG); con Pro, edita y usa funciones avanzadas solo en la app (vCard, QR, vista previa interactiva) \u2014 sin p\xe1gina web alojada por PerfectGest.\n\nClientes y datos financieros protegidos en el tel\xe9fono; no se env\xedan autom\xe1ticamente a servidores.")
B.U3=new A.K("\xbfEst\xe1n protegidos mis datos de clientes y financieros?","S\xed. Solo salen si usted comparte PDF, PNG/vCard/QR de la tarjeta o backup exportado (cifrado recomendado en Pro). Incluye presupuestos fiscales locales.")
B.Ue=new A.K("Recordatorios fiscales, calendario, \xfaltimos registros, notificaciones, anuncios, Crashlytics, idiomas?","Recordatorios locales informativos; calendario semanal en Empresa; atajos en inicio; solo notificaciones locales; sin anuncios; sin Crashlytics; PT / EN / ES.")
B.RF=new A.K("Privacidad, eliminaci\xf3n, sugerencias?","Ajustes \u2192 Ayuda y soporte para enlaces legales. Borrar datos: Ajustes \u2192 Datos en este dispositivo. Sugerencias: pesta\xf1a Empresa \u2192 suporte@perfectgestdev.com.")
B.V0=s([B.TH,B.Tc,B.TW,B.Tz,B.TX,B.U8,B.TR,B.UI,B.U3,B.Ue,B.RF],t.h)
B.V1=s(["\u0d9a\u0dca\u200d\u0dbb\u0dd2\u0dc3\u0dca\u0dad\u0dd4 \u0db4\u0dd6\u0dbb\u0dca\u0dc0","\u0d9a\u0dca\u200d\u0dbb\u0dd2\u0dc3\u0dca\u0dad\u0dd4 \u0dc0\u0dbb\u0dca\u0dc2"],t.s)
B.TU=new A.K("1. Objeto","Estes Termos regem a app PerfectGest I, para gest\xe3o empresarial no telem\xf3vel: clientes, or\xe7amentos comerciais, or\xe7amentos fiscais (aba Or\xe7/NF-e/NFS-e \u2014 documentos locais de apoio; sem emiss\xe3o electr\xf3nica de NF-e/NFS-e), caixa, ordem de servi\xe7o, lembretes fiscais e cart\xe3o de visita digital, com dados principalmente no dispositivo.\n\nDados de clientes e financeiros permanecem no aparelho e n\xe3o s\xe3o transmitidos automaticamente. Podem sair somente por ac\xe7\xe3o do utilizador (partilha de PDF, backup exportado, cart\xe3o de visita PNG/vCard/QR). Ver Pol\xedtica de Privacidade.\n\nEditor: Marcos Leandro dos Santos.")
B.S4=new A.K("2. Elegibilidade","Utilizadores maiores de 18 anos.")
B.S_=new A.K("3. Explora\xe7\xe3o, Plano Pro e assinaturas","- Ap\xf3s o download: pode explorar a app (navegar e consultar a interface) sem assinatura.\n- Opera\xe7\xf5es (criar registos, gerar PDFs de gest\xe3o, restauro de backup encriptado e demais ac\xe7\xf5es condicionadas) exigem Plano Pro. Sem assinatura, a app mostra um aviso com o plano (refer\xeancia R$ 9,90/m\xeas; pre\xe7o oficial na Google Play) e as op\xe7\xf5es Assinar ou Continuar a explorar recursos do Aplicativo.\n- Plano Pro: uso ilimitado das fun\xe7\xf5es activas, restauro de backup encriptado e cart\xe3o de visita interactivo na app \u2014 assinatura mensal ou anual via Google Play (pre\xe7o e condi\xe7\xf5es na loja).\n- Renova\xe7\xe3o autom\xe1tica at\xe9 cancelar na Play Store: Pagamentos e subscri\xe7\xf5es \u2192 Subscri\xe7\xf5es.")
B.Uq=new A.K("4. Cancelamento","Google Play Store \u2192 Pagamentos e subscri\xe7\xf5es \u2192 Subscri\xe7\xf5es.")
B.Se=new A.K("5. Direito de arrependimento (Brasil \u2014 CDC)","Direito legal de arrependimento de 7 dias corridos quando aplic\xe1vel ao consumidor brasileiro, sem preju\xedzo das regras Google Play. Reembolsos via canais Google.")
B.S6=new A.K("6. Lembretes fiscais e or\xe7amentos fiscais","Lembretes e documentos fiscais na app s\xe3o meramente informativos / de apoio; n\xe3o substituem contabilista nem constituem emiss\xe3o oficial de notas fiscais. Responsabilidade do utilizador.")
B.Ta=new A.K("7. Limita\xe7\xe3o de responsabilidade","Ferramenta de apoio; n\xe3o substitui assessoria profissional. Decis\xf5es de neg\xf3cio s\xe3o do utilizador.")
B.Si=new A.K("8. Propriedade intelectual","Licen\xe7a revog\xe1vel, n\xe3o exclusiva. Proibida engenharia inversa il\xedcita.")
B.SW=new A.K("9. Altera\xe7\xf5es","Vers\xe3o vigente publicada no URL abaixo.")
B.SM=new A.K("10. Lei e foro","Leis do Brasil; foro Caxias do Sul/RS, sem preju\xedzo do consumidor.")
B.rr=new A.K("11. Contacto","suporte@perfectgestdev.com")
