B.RL=new A.K("4. Derechos del titular (Art. 18 LGPD)","La app ofrece soporte operacional para:\n\u2022 acceso y correccion via ficha del paciente;\n\u2022 exportacion de informe LGPD (ADMIN) en PDF/CSV (cuando este disponible);\n\u2022 portabilidad via copia cifrada.\n\nPara ejercer derechos sobre datos de salud, contactar primero la clinica (controlador).")
B.Ti=new A.K("5. Seguridad recomendada (buenas practicas)","\u2022 Activar BitLocker en Windows (recomendado);\n\u2022 Usar contrasenas fuertes y perfiles adecuados (ADMIN / MEDICO / OPERADOR);\n\u2022 Activar cifrado de base de datos en la app (opcional);\n\u2022 Usar copia ZIP cifrada y guardar la contrasena en lugar seguro.")
